          "max_matching_length": 266,
          "histogram": {
            "buckets": [
...
```

Replacing `categorize_text` with `terms` works:

```
POST kibana_sample_data_logs/_search
{
  "size": 0,
  "aggs": {
    "my_terms": {
      "terms": {
        "field": "response.keyword",
        "size": 100
      },
      "aggs": {
        "histogram": {
          "date_histogram": {
            "field": "@timestamp",
            "fixed_interval": "1d"
          }
        },
        "change_point_request": {
          "change_point": {
            "buckets_path": "histogram>_count"
          }
        }
      }
    }
  }
}
```

The response shows up even when no change points get detected as `stationary`:

```
...
