### Problem Description

Synthetic source is not consistent when handling objects with `dynamic: false`. This inconsistency also results in reduced storage efficiency.

### Steps to Reproduce

```

PUT /my_index
{
  "mappings": {
    "_source": { "mode": "synthetic" },
    "properties": {
      "obj": {
        "dynamic": false,
        "properties": {
          "n": {
           "type": "long"
          }
        }
      }
    }
  }
}

PUT my_index/_doc/1
{
  "obj": 
    {
      "n": [3, 2, 1],
      "k": ["hello", "a"]
    }
}


PUT my_index/_doc/2
{
  "obj": [
    {
      "n": [3, 2, 1],
      "k": "hello"
    },
    {
      "n": [6, 5, 4],
      "k": "hello2"
    }
  ]
}
```

```
GET /my_index/_doc/1

# "n" is constructed from doc values and is sorted, "k" is stored as is (expected)
"_source": {
    "obj": {
        "k": [
            "hello",
            "a"
        ],
        "n": [
            1,
            2,
            3
        ]
    }
}

GET /my_index/_doc/2

# entire object array is stored as is, fields are not sorted and arrays are not moved to leaf fields (unexpected)
"_source": {
    "obj": [
        {
            "n": [
                3,
                2,
                1
            ],
            "k": "hello"
        },
        {
            "n": [
                6,
                5,
                4
            ],
            "k": "hello2"
        }
    ]
}
```

